cards.style:
ha-card {
  position: absolute;
  width: 1500px;
  filter: blur(2px);
  border-radius: 0 !important;
}
ha-card:before {
  content: '';
  display: block;
  position: absolute;
  left: -180px;
  height: 170px;
  width: 100%;
  background: radial-gradient(ellipse at 50% -100%, rgba(35, 46, 66, 0) 25%, rgba(35, 46, 66, 0.8) 55%, rgba(35, 46, 66, 1) 67%);
}

card.style:
ha-card {
  position: relative !important;
  margin-bottom: -164px;
  height: 164px;
  margin-top: -8px;
  margin-left: -8px;
  margin-right: -8px;
  background: none;
  animation: opacity 2s ease-in;
}
@media only screen and (max-width: 768px) {
  ha-card {
    border-radius: 0 !important;
  }
}
@keyframes opacity {
  0% { opacity: 0; }
  40% { opacity: 0; }
  100% { opacity: 1; }
}

ha-card {
  height: 84px;
  position: absolute;
  box-shadow: none;
  background: none;
  border-radius: 0;
  opacity: 0.3;
  margin-bottom: -90px;
  margin-left: -0.6em;
  margin-right: -0.6em;
}

